var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"Charade-Lotus Management Perimeter Zone\\n<color=#ffd34c>CSE Lv. 2</color>","TWN":"查雷德-洛德斯管理警戒區\\n<color=#ffd34c>CSE Lv.2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장도 참 너무한다니까~","JPN":"隊長もひどいんだから。","ENG":"How can Commander do this to me?","TWN":"隊長也真是太過分了～"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임인지, 뭔지 한껏 달아오르게 하더니. 결국 지수만 홀랑 데려가 버렸잖아.","JPN":"クリフォトゲームとか何とかで盛り上がらせておいて、結局シノだけ連れて行っちゃって。","ENG":"He got all excited about the Qliphoth Game or whatever it's called, then only took Jisoo with him.","TWN":"逆卡巴拉遊戲什麼的搞得大家熱血沸騰，結果只把智秀一個人帶走了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쯧. 덕분에 이런 지루한 일이나 맡게 되고 말이야.","JPN":"おかげでこっちはこんな退屈な仕事をやる羽目になったし。","ENG":"Tsk. Thanks to that, I'm stuck with all the boring work.","TWN":"嘖，結果讓我接了這種無聊的工作。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"배역을 가리는 배우는 바람직하지 못한 법이죠.","JPN":"立派な俳優は与えられた役に文句を言わないものです。","ENG":"An actress should not complain about the role she gets.","TWN":"挑角色的演員可不是什麼好演員。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대에게 있어서 당신은 이미 죽은 사람.","JPN":"オオカミにとってあなたはすでに死んだ人。","ENG":"To the Wolf, you are already dead.","TWN":"在狼的眼中，你已經是個死人了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만에 하나 당신 모습이 늑대에게 노출된다면, 불필요한 변수가 발생할지도 모르니까요.","JPN":"万が一あなたの存在がオオカミの目についてしまったら、不必要な変数が増えますから。","ENG":"And if the Wolf somehow sees you, unnecessary variables may occur.","TWN":"萬一你的身影被狼發現，可能會引起不必要的變數。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님은 그런 변수를 미연에 방지하기 위해, 지수 씨를 데려간 거예요.","JPN":"隊長はその可能性を防ぐため、シノさんを連れて行ったのですよ。","ENG":"Commander took Jisoo with him to prevent those variables from happening.","TWN":"為了預防這種情況，隊長才只帶走了智秀。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그딴 건 나도 알고 있거든? 잘난 척하지 말아줄래?","JPN":"そんなのあたしだって知ってるけど？　偉そうに説教するのやめてくれる？","ENG":"I know that! So will you stop acting all high and mighty in front of me?","TWN":"那種事我也知道！別自以為是了好嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서? 얼마나 더 가야 하는 건데?","JPN":"で、あとどれぐらい行けばいいの？","ENG":"So? How much further do we have to go?","TWN":"所以呢？還要走多久？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거의 다 왔습니다. 우리는 이미 <color=#ffd34c>달</color>의 영향력 아래에요.","JPN":"もうすぐです。私たちはすでに<color=#ffd34c>月</color>の影響下にいます。","ENG":"We're almost there. We are already under the <color=#ffd34c>moon's</color> influence.","TWN":"快到了。我們已經在<color=#ffd34c>月亮</color>的影響範圍內了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 말만 벌써 세 번째라고. 애초에 이렇게 해가 밝은데 무슨 달을 보겠다는 거야?","JPN":"それもう三回目だよ。そもそもこんな明るい時間に月を見るってどういうこと？","ENG":"You said that three times already. Why are we going to see the moon when the sun's shining this bright?","TWN":"你都已經說了三次了。但是太陽這麼亮，怎麼可能看到月亮呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>세계를 만드는 법칙</color>이란 게 정말 달이랑 관련 있긴 한 거야?","JPN":"<color=#ffd34c>世界を作る法則</color>ってのは、本当に月と関係あるの？","ENG":"Does the moon even have anything to do with <color=#ffd34c>the law of creating a world</color>?","TWN":"那個<color=#ffd34c>創造世界的法則</color>真的會和月亮有關？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가끔은 머리를 좀 써보도록 하세요. 리트리버.","JPN":"たまには頭を使ってみてください、レトリーバー。","ENG":"Try using that brain of yours, retriever.","TWN":"有時候也動動腦子吧，獵犬。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한낮에 달을 볼 수 있는 방법이 전혀 없는 건 아니랍니다.","JPN":"真昼に月を見る方法はあるんですよ。","ENG":"There are still ways to see the moon in the middle of the day.","TWN":"並不是完全沒有辦法在白天看到月亮。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"옛 선인들은 모든 생명체가 달에서부터 기원했다고 주장했죠.","JPN":"昔の先人たちは、すべての生命の起源は月にあると主張していました。","ENG":"Ancient beings claimed that all living organisms originated from the moon.","TWN":"古人曾主張所有生命都起源於月亮。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은 종교적인 이야기로 치부되지만, 과학적으로도 근거가 없는 주장은 아니에요.","JPN":"今では宗教的な話だと思われますが、科学的には根拠のない話でもないのです。","ENG":"Though it is now dismissed as part of some religion, it is not a scientifically unfounded claim.","TWN":"雖然現在被認為是宗教故事，但從科學上講，這個說法也並非毫無根據。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오래전, 거대한 천체가 지구와 충돌하면서 떨어져 나간 파편이 달이라는 주장도 있으니까요.","JPN":"月は遠い昔、巨大な天体が地球と衝突した時飛ばされた破片だという説もありますので。","ENG":"There is also a claim that the moon was a piece of debris that fell off from the Earth when a huge celestial body collided with it long ago.","TWN":"很久以前，有人認為是一顆巨大的天體與地球相撞，脫落的碎片形成了月球。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 주장에 따르면 그렇게 생성된 달의 기조력에 의해, 지구는 조수간만의 차가 발생하고.","JPN":"その説によると、そうやって生成された月の起潮力によって地球には干満の差が発生し……","ENG":"According to that claim, the Earth's tidal difference occurred due to the moon's tidal force.","TWN":"根據這一主張，是由此生成的月球引力使地球產生了潮汐變化。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"덕분에 지구는 생명체가 탄생할 수 있는 환경을 갖추게 되었다고 하죠.","JPN":"そのおかげで地球は生命体が生まれる環境になったそうです。","ENG":"Which allowed the Earth to have an environment that was suitable for life.","TWN":"多虧了它，地球才具備了孕育生命的環境。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"선생님~? 그거 시험에 나오나요~?","JPN":"先生～？　それってテストに出ますか～？","ENG":"Miss Swan? Will this be on the test?","TWN":"老師～？這題會考嗎～？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"조용히 하세요. 본론은 아직 시작도 안 했으니까.","JPN":"お静かに。まだ本題に入ってません。","ENG":"Hush. I haven't even gotten to the main topic.","TWN":"安靜點。正題還沒開始呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"구 관리국의 데이터에 따르면, 달의 뒷면은 <color=#ffd34c>세피라</color>와 접촉할 가능성이 가장 높은 지점.","JPN":"旧管理局のデータによると、月の裏側は<color=#ffd34c>セフィラ</color>と接触する可能性がもっとも高い地点。","ENG":"According to the Old Administration's data, the dark side of the moon is the most likely point of contact with <color=#ffd34c>Sephira</color>.","TWN":"根據舊管理局的資料，月球背面是最有可能接觸到<color=#ffd34c>塞菲拉</color>的地點。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 잔존 세력이 숨어든 북방합의체 역시 진작부터 이 사실을 알고 있었습니다.","JPN":"残存勢力が忍び込んでいる北方合意体も、この事実には気づいています。","ENG":"The Northern Union, where the remnants of its forces have gone to hide, has known about this long since.","TWN":"那個藏匿著殘餘勢力的北方和議會也早就知道了這個事實。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 수년 전, 그들은 달의 뒷면을 조사하기 위해 탐사대를 보냈어요.","JPN":"だから数年前、彼らは月の裏側を調査するために探査隊を送り出しました。","ENG":"So, a few years ago, they sent an expedition to study the dark side of the moon.","TWN":"所以幾年前，他們曾派遣探險隊去調查過月球的背面。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 결과는 참혹했죠. 탐사대원 대부분이 목표지점에 도달하기 전에 사망해 버렸고.","JPN":"しかし結果は悲惨なものでした。隊員のほとんどが目標地点に辿り着く前に死亡。","ENG":"However, the results were disastrous. Most of the expedition crew members died before reaching their destination.","TWN":"結果很慘烈，大部分探險隊員在到達目標地點之前就已經死亡了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 유일한 생존자마저 달의 뒷면에서 무엇을 관측했는지 전혀 기억하지 못했어요.","JPN":"唯一の生存者も、月の裏側で観測したものについてまったく覚えていませんでした。","ENG":"And the sole survivor can't remember what she had observed over there.","TWN":"就連那個唯一的倖存者也完全不記得在月球背面觀察到了什麼。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국, 얼마 안 가서 행방까지 감추어 버렸고요.","JPN":"しかも帰還からまもなくして行方をくらませてしまいました。","ENG":"Afterwards, her whereabouts became unclear.","TWN":"最終，她也很快就消失得無影無蹤了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서? 결론이 뭔데? 북방합의체도 실패한 달 관측을 어떻게 하겠다고?","JPN":"で、結論はなに？　北方合意体も失敗した月の観測を、どうやってやるつもりなの？","ENG":"So? What are you trying to say? You're going to somehow observe the dark side of the moon that even the Northern Union failed to do?","TWN":"所以呢？結論是什麼？連北方和議會都失敗了的計畫，你打算怎麼做？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"여기 어딘가 고성능 망원경이라도 숨겨져 있다는 뜻이야?","JPN":"この辺のどこかに高性能な望遠鏡でも隠されてるわけ？","ENG":"Or are you trying to tell me that there's a high-tech telescope hidden somewhere around here?","TWN":"你的意思是這裡還藏著高性能望遠鏡嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그런 건 필요 없답니다.","JPN":"そんなものは必要ありません。","ENG":"There will be no need for that.","TWN":"不需要那種東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 예상대로라면, 달은 때가 되면 스스로 그 뒷면을 우리에게 보여줄 테니까요.","JPN":"私の予想どおりなら、月は時が来れば自らその裏側を私たちに見せてくれるはずです。","ENG":"If I am correct, the moon will show us its dark side when the time comes.","TWN":"按照我的推測，月亮到時候會自己向我們展示它的背面。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"스스로 모습을 보여줘?","JPN":"自ら見せてくれる？","ENG":"The moon will show its dark side to us?","TWN":"自己……展示？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 잘은 모르겠지만, 아무튼 그때라는 게 클리포트 게임이 끝나는 순간이라는 거지?","JPN":"ちっ……よくわからないけど、その時がクリフォトゲームが終わる瞬間ってことだよね？","ENG":"Tch, I'm not sure what this is all about, but it's going to happen the moment the Qliphoth Game is over, right?","TWN":"嘖，雖然不太清楚，但總之那個時候就是逆卡巴拉遊戲結束的瞬間，對吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"훗, 이제야 조금 말귀를 알아듣는군요.","JPN":"ふっ、やっと理解が追いついたようですね。","ENG":"Hmm, you're beginning to understand.","TWN":"嗯，現在總算有點開竅了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"간식이라도 드릴까요, 리트리버?","JPN":"ご褒美におやつでもあげましょうか、レトリーバー？","ENG":"Do you want a treat, retriever?","TWN":"要不要給你點小零食，獵犬？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"됐거든? 속 시커먼 여자가 주는 건 안 먹어.","JPN":"いらないよ。腹黒女のくれるもんは食べないから。","ENG":"No thanks. I don't eat anything given to me by a shady woman.","TWN":"不要，我才不吃你這個居心不良的女人給的東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님은 클리포트 게임이 끝나면 세계가 변할 것이라고 했죠.","JPN":"隊長は、クリフォトゲームが終われば世界が変わると言っていました。","ENG":"Commander said the world will change after the Qliphoth Game, right?","TWN":"隊長說過，逆卡巴拉遊戲結束後，世界將會改變。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임은 <color=#ffd34c>어떤 존재</color>에 의해 이루어지는 것.","JPN":"クリフォトゲームは<color=#ffd34c>ある存在</color>によって行われるもの。","ENG":"The Qliphoth Game is created by a <color=#ffd34c>certain being</color>.","TWN":"逆卡巴拉遊戲依託於<color=#ffd34c>某種存在</color>。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임의 승리로 인해, 어떤 식으로든 세계가 변화하게 된다면.","JPN":"ゲームの勝利により、どんな形であれ世界が変化を遂げることになるなら。","ENG":"If winning the game changes the world in some way.","TWN":"如果因為勝利，世界以某種方式發生了變化。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 틀림없이 세계를 만드는 법칙, <color=#ffd34c>세피로트 나무</color>가 어떤 식으로든 그 존재가 규정한 규칙에서 벗어났다는 걸 뜻해요.","JPN":"それは間違いなく世界を作る法則、<color=#ffd34c>セフィロト</color>が何らかの経緯でその存在が規定した規則から外れたということになります。","ENG":"Then, it will certainly mean that the law of creating a world, the <color=#ffd34c>Tree of Sephiroth</color>, has somehow deviated from the rules the being had decided.","TWN":"那無疑表示創造世界的法則，<color=#ffd34c>生命樹</color>在某種程度上偏離了它所規定的規則。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"잠깐, 하늘이……?","JPN":"ちょっと、空が……？","ENG":"Wait, the sky...","TWN":"等等，天空……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"서서히 어두워지고 있잖아……?","JPN":"だんだん暗くなってる……？","ENG":"Why's it slowly getting darker...?","TWN":"漸漸變暗了……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시작됐군요. <color=#ffd34c>개기일식</color>이.","JPN":"始まりましたね。<color=#ffd34c>皆既日食</color>が。","ENG":"It has started. The <color=#ffd34c>total solar eclipse</color>.","TWN":"……它開始了。<color=#ffd34c>日全食</color>。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"개기일식이라고?","JPN":"皆既日食？","ENG":"Total solar eclipse?","TWN":"你說日全食？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 대낮에 달을 볼 수 있는 방법이라는 게……?","JPN":"じゃあ、真昼に月を観測できる方法って……？","ENG":"That's what you meant by seeing the moon in broad daylight...?","TWN":"那麼，能在白天看到月亮的方法是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금 이 순간, 우리가 서있는 이 곳은 태양과 달 그리고 지구가 일직선으로 정렬하는 곳.","JPN":"今この瞬間、私たちが立っているここは太陽と月、そして地球が一直線に並ぶ地点。","ENG":"In this moment, when the sun, moon, and Earth are aligned.","TWN":"此刻，我們站在這裡，正是太陽、月亮和地球連成一線的地方。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"동시에 태양을 가린 달이 자전하면서 스스로 그 뒷면을 보여주게 되는 곳이랍니다.","JPN":"同時に、太陽を隠した月が自転し、裏側を自ら見せてくれる場所です。","ENG":"At the same time, the moon that covers the sun will revolve and show us its dark side.","TWN":"那時，遮住太陽的月亮自然會向我們展示它的背面。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 뿐만이 아니에요.","JPN":"それだけではありません。","ENG":"But that's not all.","TWN":"不僅如此。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아름다운 미의 태양을 중심으로…….","JPN":"美しい美の太陽を中心に……","ENG":"Centered around the sun's beauty...","TWN":"以美麗的太陽為中心……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왕관의 자리에 해왕성이, 지혜의 자리에 천왕성이, 이해의 자리에 토성이.","JPN":"王冠の座に海王星が、知恵の座に天王星が、理解の座に土星が。","ENG":"Neptune is positioned on the seat of the crown, Uranus on wisdom, and Saturn on understanding.","TWN":"佔據王冠之位的海王星、智慧之位的天王星、理解之位的土星……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자비로운 목성과 근엄한 화성. 그리고 승리의 금성과 영광의 수성이 제 위치를 찾을 겁니다.","JPN":"慈悲の木星に威厳の火星、そして勝利の金星と栄光の水星が戻るべき場所に戻ります。","ENG":"Jupiter on the kindness, Mars on the discipline, Venus on the victory, and Mercury on the glory will also find their places.","TWN":"仁慈的木星和嚴厲的火星，然後是勝利的金星和榮耀的水星將一一找到它們的位置。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 천체가 원래 위치를 찾아 정렬하는 순간과 클리포트 게임이 끝나는 순간…….","JPN":"すべての天体があるべき場所に戻る瞬間と、クリフォトゲームが終わる瞬間……","ENG":"The moment all the planets find their original positions, and the moment the Qliphoth Game ends...","TWN":"所有天體回到原位並排列整齊的那一刻，也是逆卡巴拉遊戲結束的那一刻……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 두 순간이 교묘하게 맞물려 떨어지는 게 과연 우연일까요?","JPN":"二つの瞬間がこうもぴったり重なるのは、果たして本当に偶然なのでしょうか。","ENG":"Do you think it is a coincidence that these two moments are so intricately intertwined?","TWN":"這兩方巧妙地重合，真的是碰巧嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그게 아니라면, <color=#ffd34c>무언가</color>의 의지 표현일까요?","JPN":"それとも、<color=#ffd34c>何か</color>の意思の現れなのでしょうか。","ENG":"If not, is it the will of <color=#ffd34c>some being</color>?","TWN":"如果不是，那是<color=#ffd34c>某種</color>意志的表達嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 아주 오랜 시간 동안 세피로트 나무를 조사해 왔습니다.","JPN":"私はとても長い間、セフィロトを調べてきました。","ENG":"I've been researching the Tree of Sephiroth for a very long time.","TWN":"我已經研究生命樹很長時間了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"틀림없어요, 퍼스트윙.","JPN":"間違いありません、ファーストウイング。","ENG":"I am sure of it, Firstwing.","TWN":"我很確定，弗斯特薇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임이 끝나고 어떤 식으로든 세계가 변화한다면, 그 가능성이 가장 큰 곳은.","JPN":"ゲームが終わり、どんな形であれ、世界に変化が訪れるのなら。その可能性がもっとも高いのは。","ENG":"If the world changes somehow after the Qliphoth Game ends, the place with the most possibilities, is <color=#ffd34c>here</color>.","TWN":"如果結束後世界會以某種方式改變，那麼最有可能的地方是——"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"개기일식으로 달의 뒷면을 직접 관측할 수 있는 <color=#ffd34c>여기</color>예요.","JPN":"皆既日食で月の裏側を直接観測できる<color=#ffd34c>ここ</color>です。","ENG":"Where the dark side of the moon can be observed during a total solar eclipse.","TWN":"透過日全食可以直接觀測到月球背面的<color=#ffd34c>這裡</color>。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저기 스완 선생님~?","JPN":"あの、スワン先生～？","ENG":"Um, Ms. Claire?","TWN":"那個，史旺老師～？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"확실한 거 맞나요? 어째 침식체들이 점점 몰려드는 것 같은데요?","JPN":"それって本当ですか～？　侵食体がどんどん集まってきてるんですけど。","ENG":"Are you absolutely sure about this? Because I see a lot of C.O.s gathering here.","TWN":"你確定嗎？怎麼感覺侵蝕體越來越多了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 수업을 귀 기울여 듣지 않으셨군요. 리트리버.","JPN":"私の授業に集中していなかったのですね、レトリーバー。","ENG":"You seem to have not paid attention during my class, retriever.","TWN":"你沒有認真聽我的課喔，獵犬。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가능성을 탐하는 존재가 세피라 관측 지점에 몰려드는 건, 이상한 일이 아니에요.","JPN":"可能性を求める存在がセフィラの観測地点に集まってくるのは、おかしいことではありません。","ENG":"It's not strange for beings that seek possibilities to gather around the Sephira observation point.","TWN":"尋求著可能性的存在會聚集在塞菲拉觀測點，這並不奇怪。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대장님 또한 그걸 예측하셨으니, 당신을 제 호위로 붙여주신 거 아닐까요?","JPN":"隊長もそれを予測していたからこそ、あなたを私の護衛に付き添わせたのでは？","ENG":"Commander seems to have also predicted this and tasked you as my guard, no?","TWN":"隊長也預測到了這一點，所以才派你來保護我，不是嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"예이, 예이~ 어련하시겠어.","JPN":"はい、はい～おっしゃる通りで。","ENG":"Yeah, yeah. Of course, he did.","TWN":"是～是～就是這樣沒錯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"안 싸울 거면, 멀찍이 떨어져 있어. 괜히 근처에 있다가 다쳐도 책임 못 진다?","JPN":"戦わないなら下がってて。近くをうろうろして怪我しても知らないからね。","ENG":"If you're not going to fight, stay back. I'm not taking the fall for you getting injured because you stayed too close.","TWN":"不想戰鬥的話，就離遠點。要是待在附近受傷了，我可不負責？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론이에요. 저는 배우인 동시에 각본가.","JPN":"もちろんです、私は俳優でありながら脚本家。","ENG":"Of course. I'm a screenwriter as well as an actress.","TWN":"當然了。我既是演員，也是編劇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"끝의 시작을. 세계가 변화하는 순간을. 운명과 숙명이 교차하여 자아낸 부조리극을…….","JPN":"終わりの始まりを、世界が変化を遂げる瞬間を、運命と宿命が交差して織りなす不条理劇を……","ENG":"The beginning of the end. The moment the world changes. The absurd drama created by the clash of fate and destiny...","TWN":"終結的開始。世界變化的瞬間。命運與宿命交織而成的荒誕劇……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본가로서, 단 한 순간도 놓치고 싶지 않으니까요.","JPN":"脚本家として、すべてをこの目に収めたいので。","ENG":"As a screenwriter, I wouldn't want to miss a single moment of this.","TWN":"作為編劇，我不想錯過任何一個瞬間。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};